  if (auth != null) auth.syncLike(song.serverId, liked);
  notifyListeners();
}

@override
Future<List<({Song song, int likedCount, int playCount})>> getMostLiked(List<Song> knownSongs) =>
    _historyService.getMostLiked(knownSongs);

